var e=JSON.parse(`[{"id":"L9_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"뭐야, 정전? 담당자가 누구죠?","JPN":"あら、停電？　担当者は誰ですか？","ENG":"Huh? A blackout? Who's in charge?","TWN":"怎麼回事，停電嗎？是誰負責的？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"호란 님이십니다.","JPN":"ホラン様です。","ENG":"Ms. Horan, Madam.","TWN":"是小蘭小姐。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"흥. 패배도 모자라서 자기 일도 제대로 못하는군요.","JPN":"ふん。負けた上に自分の仕事もちゃんとできないなんて。","ENG":"Hmph. Wasn't losing to those brats embarrassing enough? Now she can't even do her job right.","TWN":"哼，比賽輸掉不打緊，連自己分內的事都做不好嗎！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"우리 조직에 어울리는 인물상이 아니에요. 이번 일만 끝나면 함선 밖으로 던져 버려야겠어.","JPN":"この組織に合わないのよ。今度の仕事が終わったら艦船の外へ投げ捨てた方がいいわ。","ENG":"I don't believe she fits into our organization. I'll have to get her thrown over the railing after this is all over.","TWN":"不符合我們組織的形象，等這次的事情結束後就把她逐出艦船！"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"예? 호란 님은 오래 전부터 헤이븐 님 밑에서 일하신 분 아닙니까?","JPN":"え？　ホラン様は昔からヘイブン様の下で働いてこられた方ではないですか。","ENG":"But Madam...! Hasn't Ms. Horan been with Mr. Haven for a long time?","TWN":"什麼？小蘭小姐不是從很久以前就在天堂大哥手下做事嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그래서 그 기름내 나는 계집애가 나보다 더 오래 일했어?","JPN":"その油臭い女が私より長く働いたとでも？","ENG":"Are you implying that the girl covered in grime and grease has known Haven for longer than I have?","TWN":"那個自以為是老鳥的丫頭資歷有比我久嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님은 지금 자리를 비우셨고, 호란은 자기 책임도 다하지 못하는데.","JPN":"ヘイブン様は今留守で、ホランは自分の責任も果たせてないわ。","ENG":"Mr. Haven's currently away, and Horan can't even fulfill her responsibilities.","TWN":"天堂先生現在不在，小蘭又無法承擔責任，"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"말이 더 필요한가?","JPN":"これ以上説明が必要かしら。","ENG":"Now was there anything else?","TWN":"還有需要我多說嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"알았으면 입단속 잘하세요. 귀찮게 소란 일으키지 말고.","JPN":"わかったなら他言はしないようにね。騒いで面倒起こさないで。","ENG":"Know your place. And don't cause any more bothersome disturbances.","TWN":"有聽懂的話就管好你的嘴巴，不要引起不必要的事端。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"……명심하겠습니다.","JPN":"……肝に銘じます。","ENG":"...Understood, Madam.","TWN":"……是，遵命。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"독사과는 어때요. 반항은 없던가요?","JPN":"毒リンゴの方はどうですか。抵抗はありませんか？","ENG":"How's Poison Apple? Any resistance from her?","TWN":"毒蘋果怎麼樣？沒有反抗嗎？"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"MOB_HAVEN_NULL_B","text":{"KOREA":"예. 이제 막 통제권을 얻었습니다. 발각되기 쉬워서 사용하진 않았습니다만.","JPN":"はい。たった今統制権を手に入れました。簡単にバレるので使用してはいませんが。","ENG":"We just got control over her, ma'am. But any sudden change will raise suspicion, so we haven't used it yet.","TWN":"是，我們已經取得控制權，只是太容易被發現所以沒使用。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아주 좋아요. 내가 원한 게 바로 그런 능동적인 태도라니까.","JPN":"上出来です。私がほしかったのはそういう能動的な態度なの。","ENG":"Very good. That is exactly what I wanted, a can-do attitude.","TWN":"非常好，我要的就是這種主動的態度。"},"stage":{"bg":"ROOM_02","slots":{"L":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"흥, 이렇게 쉬울 줄 알았으면 바로 불러들일 걸 그랬어.","JPN":"ふん、こんなに簡単なことならすぐ呼び寄せるんだったわ。","ENG":"Hmph. If it was going to be this easy, I should've done this sooner.","TWN":"哼，早知道這麼容易，我就立刻把人引回來。"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그랬으면 의장님께 기생체를 바치고 평의회 의원 자리도 얻을 수 있었을 텐데……","JPN":"そうすれば議長に寄生体を贈って評議会の議員席も得られたでしょうに……","ENG":"Then, I could present the Chairman with the parasite and earn a spot on the Dark Council...","TWN":"這樣就可以將寄生物獻給議長，還能得到評議會議員的位置……"},"stage":{"bg":"ROOM_02","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};